// Extract content from webhook payload
// Handles different payload shapes from different sources
const body = $input.item.json.body || $input.item.json;

return {
  json: {
    message_text: body.text || body.message || '',
    user_id: body.user || body.user_id || 'anonymous',
    source: body.source || 'manual',
    timestamp: body.timestamp || new Date().toISOString(),
    metadata: body.metadata || {}
  }
};

// Parse Claude API response
const response = $input.item.json;
const content = response.content && response.content[0] && response.content[0].text;

if (!content) {
  throw new Error('No content in Claude response');
}

// Extract JSON from response (remove markdown code blocks if present)
let jsonText = content.trim();
if (jsonText.startsWith('```json')) {
  jsonText = jsonText.replace(/```json\n?/g, '').replace(/```/g, '').trim();
}

const classified = JSON.parse(jsonText);

// Get original message data
const originalData = $node['Extract Content'].json;

// Generate unique file_name: auto_{source}_{unix_timestamp}
const timestamp = new Date().getTime();
const file_name = `auto_${originalData.source}_${timestamp}`;

return {
  json: {
    file_name: file_name,
    type: null,
    summary: classified.summary || '',
    tags: classified.tags || [],
    entities: classified.entities || [],
    emotional_tone: null,
    source: originalData.source,
    themes: [],
    concepts: [],
    keywords: [],
    mime_type: 'text/plain',
    cluster: null,
    related_ids: [],
    date_estimated: classified.date_estimated || new Date().toISOString().split('T')[0],
    timeline_group: classified.timeline_group || '2024-2026',
    narrative_role: classified.narrative_role || 'exploration'
  }
};
